import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote — base premiums", () => {
    it("returns 5 G for an empty item list (processing fee only)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it.todo("returns 105 G for a single sword (100 base + 5 fee)");
    it.todo("returns 65 G for a single amulet (60 base + 5 fee)");
    it.todo("returns 85 G for a single staff (80 base + 5 fee)");
    it.todo("returns 45 G for a single potion (40 base + 5 fee)");
    it.todo("returns 30 G for a single rune component (25 base + 5 fee)");
    it.todo("returns 165 G for a sword and an amulet (100 + 60 + 5 fee)");
  });

  describe("Quote — component block pricing", () => {
    it.todo("returns 55 G for 2 runes (2 × 25 + 5 fee)");
    it.todo("returns 65 G for 3 runes (block of 3 alike = 60 + 5 fee)");
    it.todo("returns 105 G for 4 runes (no block: 4 × 25 + 5 fee)");
    it.todo("returns 80 G for 2 runes + 1 moonstone (no block: different types, 3 × 25 + 5 fee)");
    it.todo("returns 125 G for 3 runes + 3 moonstones (two blocks: 60 + 60 + 5 fee)");
  });

  describe("Quote — item-specific modifiers", () => {
    it.todo("adds 50% curse surcharge to cursed item base premium");
    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
    it.todo("does not add high-enchantment surcharge for enchantment level 4");
    it.todo("applies both curse and high-enchantment surcharges to same item");
    it.todo("applies item-specific surcharges only to the affected item in a multi-item policy");
  });

  describe("Quote — policy-wide modifiers", () => {
    it.todo("adds 10% first-insurance surcharge to policy base premium");
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up discount on second quote");
    it.todo("applies both loyalty and follow-up discounts together");
  });

  describe("Quote — rounding", () => {
    it.todo("rounds premium up in MHPCO's favor");
  });

  describe("Quote — integration", () => {
    it.todo("newcomer with a cursed sword: premium 165 G");
    it.todo("long-standing customer second contract with cursed high-enchantment sword: premium 160 G");
  });

  describe("Claim — basic payout", () => {
    it.todo("applies 100 G deductible per damaged item");
    it.todo("reimburses standard damage at full amount minus deductible");
    it.todo("reimburses component damage at full amount minus deductible");
  });

  describe("Claim — enchantment and material modifiers", () => {
    it.todo("reimburses enchantment >= 8 items at 50% of damage then deductible");
    it.todo("reimburses dragon-material items at full damage minus deductible");
    it.todo("applies 50% rule when both enchantment >= 8 and dragon material");
  });

  describe("Claim — cap", () => {
    it.todo("caps total payout at 2x insurance sum per policy");
    it.todo("tracks remaining cap across multiple claims");
  });

  describe("Claim — multiple items", () => {
    it.todo("applies deductible per damaged item in a multi-damage event");
    it.todo("handles multiple items of the same type in a policy");
  });

  describe("Claim — payout rounding", () => {
    it.todo("rounds payout down in MHPCO's favor");
  });

  describe("Error handling", () => {
    it.todo("rejects unknown item type in quote");
    it.todo("rejects claim referencing item not in policy");
    it.todo("rejects claim with more damages than insured items of that type");
    it.todo("rejects negative damage amount");
  });
});

