const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

export function processScenario(scenario: unknown): { results: unknown[] } {
  const s = scenario as { steps: Array<{ op: string; items?: Array<{ type: string }> }> };
  const results = s.steps.map((step) => {
    if (step.op === "quote") {
      const items = step.items ?? [];
      const basePremium = items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
      return { premium: basePremium + PROCESSING_FEE };
    }
    return {};
  });
  return { results };
}

