const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface Step {
  op: string;
  items?: Array<{ type: string }>;
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

function computeComponentPremium(items: Array<{ type: string }>): number {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  let premium = 0;
  for (const [type, count] of counts) {
    if (count === BLOCK_SIZE) {
      premium += BLOCK_PREMIUM;
    } else {
      premium += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }
  return premium;
}

function computeQuotePremium(items: Array<{ type: string }>): number {
  const standardItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
  const standardPremium = standardItems.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
  const componentPremium = computeComponentPremium(items);
  return standardPremium + componentPremium + PROCESSING_FEE;
}

export function processScenario(scenario: Scenario): { results: unknown[] } {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const items = step.items ?? [];
      return { premium: computeQuotePremium(items) };
    }
    return {};
  });
  return { results };
}

