  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

function computeComponentPremium(items: Array<{ type: string }>): number {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  let premium = 0;
  for (const [type, count] of counts) {
    if (count === BLOCK_SIZE) {
      premium += BLOCK_PREMIUM;
    } else {
      premium += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }
  return premium;
}

function computeQuotePremium(items: Item[]): number {
  const standardItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
  let policyBase = 0;
  let itemSurcharges = 0;
  for (const item of standardItems) {
    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
    policyBase += basePremium;
    if (item.cursed) {
      itemSurcharges += basePremium * 0.5;
    }
    if ((item.enchantment ?? 0) >= 5) {
      itemSurcharges += basePremium * 0.3;
    }
  }
  const componentPremium = computeComponentPremium(items);
  policyBase += componentPremium;
  const firstInsurance = policyBase * 0.1;
  return policyBase + itemSurcharges + firstInsurance + PROCESSING_FEE;
}

export function processScenario(scenario: Scenario): { results: unknown[] } {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const items = step.items ?? [];
      return { premium: computeQuotePremium(items) };
    }
    return {};
  });
  return { results };
}

