```
function computeClaimResult(policy: Policy, damages: Damage[]): { payout: number; remainingCap: number } {
  let totalPayout = 0;               // binding(1) + constant(1) + assignment(6)
  for (const damage of damages) {    // binding(1) + binding(1) + loop(5)
    const item = policy.items.find((i) => i.type === damage.itemType);  // binding(1) + binding(1) + invocation(2) + invocation(2)
    let reimbursement = damage.amount;  // binding(1) + assignment(6)
    if (item && (item.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD) {  // conditional(4) + constant(1) + invocation(2)
      reimbursement = damage.amount * CLAIM_HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;  // assignment(6) + invocation(2)
